"""This is Updated protoType of 'conditionsdemo1.pybecause that code is slightly repetitive"""x = int(input("What's X ? "))y = int(input("What's Y ? "))if x < y :    print("'X' is less than 'Y' !")elif x > y :    print("'X' is greater than 'Y' !")elif x == y :    print("'X' equals to 'Y' !")"""In Last Case we can also use else :   print("'X' equals to 'Y')"""